const Redis = require('ioredis');

const redis = new Redis({
  host: process.env.REDIS_HOST || '127.0.0.1',
  port: process.env.REDIS_PORT || 6379,
  retryStrategy(times) {
    const delay = Math.min(times * 50, 2000);
    return delay;
  }
});

// Key naming conventions
const COUPON_KEY = (code) => `coupon:${code}`;
const COUPON_USAGE_KEY = (code) => `coupon:${code}:used_by`;
const USER_COUPONS_KEY = (userId) => `user:${userId}:coupons`;
const COUPON_LOCK_KEY = (code, userId) => `lock:coupon:${code}:${userId}`;

/**
 * Create a new coupon in the system
 */
async function createCoupon({
  code,
  discountType,
  discountValue,
  maxUses,
  expiresAt,
  minOrderAmount = 0,
  description = ''
}) {
  const couponKey = COUPON_KEY(code);

  const exists = await redis.exists(couponKey);
  if (exists) {
    throw new Error(`Coupon code "${code}" already exists`);
  }

  const couponData = {
    code,
    discountType,       // 'percentage' or 'fixed'
    discountValue,      // e.g., 20 for 20% or 20 for $20
    maxUses,            // max number of total redemptions
    currentUses: 0,
    expiresAt,          // ISO timestamp string
    minOrderAmount,
    description,
    active: 'true',
    createdAt: new Date().toISOString()
  };

  await redis.hmset(couponKey, couponData);

  // Set TTL on the coupon key so it auto-cleans after expiry + buffer
  const expiresDate = new Date(expiresAt);
  const ttlSeconds = Math.floor((expiresDate.getTime() - Date.now()) / 1000) + 86400; // +1 day buffer
  if (ttlSeconds > 0) {
    await redis.expire(couponKey, ttlSeconds);
  }

  console.log(`Coupon "${code}" created successfully`);
  return couponData;
}

/**
 * Redeem a coupon using Redis transactions (WATCH/MULTI/EXEC) for atomic read-modify-write
 * This handles race conditions during high traffic sales events
 */
async function redeemCoupon(couponCode, userId, orderAmount) {
  const couponKey = COUPON_KEY(couponCode);
  const usageKey = COUPON_USAGE_KEY(couponCode);
  const userCouponsKey = USER_COUPONS_KEY(userId);
  const lockKey = COUPON_LOCK_KEY(couponCode, userId);

  // Distributed lock to prevent the same user from double-redeeming simultaneously
  const lockAcquired = await redis.set(lockKey, '1', 'NX', 'EX', 10);
  if (!lockAcquired) {
    throw new Error('Another redemption is already in progress for this coupon and user. Please try again.');
  }

  try {
    // Use an optimistic locking loop with WATCH/MULTI/EXEC
    const MAX_RETRIES = 5;
    for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
      // Create a new isolated client for WATCH transaction
      const watchClient = redis.duplicate();

      try {
        // WATCH the coupon key and usage set for changes
        await watchClient.watch(couponKey, usageKey);

        // --- READ PHASE: Validate the coupon ---
        const couponData = await watchClient.hgetall(couponKey);

        if (!couponData || !couponData.code) {
          watchClient.unwatch();
          watchClient.disconnect();
          throw new Error(`Coupon "${couponCode}" does not exist`);
        }

        if (couponData.active !== 'true') {
          watchClient.unwatch();
          watchClient.disconnect();
          throw new Error(`Coupon "${couponCode}" is no longer active`);
        }

        // Check expiration
        const now = new Date();
        const expiresAt = new Date(couponData.expiresAt);
        if (now > expiresAt) {
          watchClient.unwatch();
          watchClient.disconnect();
          throw new Error(`Coupon "${couponCode}" has expired`);
        }

        // Check max uses
        const currentUses = parseInt(couponData.currentUses, 10);
        const maxUses = parseInt(couponData.maxUses, 10);
        if (currentUses >= maxUses) {
          watchClient.unwatch();
          watchClient.disconnect();
          throw new Error(`Coupon "${couponCode}" has reached its maximum number of uses`);
        }

        // Check if this user already used this coupon
        const alreadyUsed = await watchClient.sismember(usageKey, userId);
        if (alreadyUsed) {
          watchClient.unwatch();
          watchClient.disconnect();
          throw new Error(`User "${userId}" has already used coupon "${couponCode}"`);
        }

        // Check minimum order amount
        const minOrderAmount = parseFloat(couponData.minOrderAmount);
        if (orderAmount < minOrderAmount) {
          watchClient.unwatch();
          watchClient.disconnect();
          throw new Error(`Order amount $${orderAmount} does not meet minimum $${minOrderAmount} for coupon "${couponCode}"`);
        }

        // Calculate discount
        const discount = calculateDiscount(couponData, orderAmount);

        // --- MODIFY/WRITE PHASE: Atomic transaction ---
        const multi = watchClient.multi();

        // Increment usage count
        multi.hincrby(couponKey, 'currentUses', 1);

        // Add user to the set of users who used this coupon
        multi.sadd(usageKey, userId);

        // Track which coupons this user has used
        multi.sadd(userCouponsKey, couponCode);

        // If this is the last use, deactivate the coupon
        if (currentUses + 1 >= maxUses) {
          multi.hset(couponKey, 'active', 'false');
        }

        // Execute the transaction
        const results = await multi.exec();
        watchClient.disconnect();

        if (results === null) {
          // Transaction was aborted due to WATCH conflict — retry
          console.log(`Transaction conflict on attempt ${attempt + 1} for coupon "${couponCode}", retrying...`);
          // Small jittered backoff
          await sleep(Math.random() * 50 * (attempt + 1));
          continue;
        }

        // Transaction succeeded
        const redemptionResult = {
          success: true,
          couponCode,
          userId,
          originalAmount: orderAmount,
          discountType: couponData.discountType,
          discountValue: parseFloat(couponData.discountValue),
          discountApplied: discount,
          finalAmount: Math.max(0, orderAmount - discount),
          redeemedAt: new Date().toISOString(),
          remainingUses: maxUses - (currentUses + 1)
        };

        console.log(`Coupon "${couponCode}" redeemed by user "${userId}": -$${discount.toFixed(2)}`);
        return redemptionResult;

      } catch (err) {
        watchClient.disconnect();
        // Re-throw validation errors immediately (no retry needed)
        if (err.message.includes('does not exist') ||
            err.message.includes('no longer active') ||
            err.message.includes('has expired') ||
            err.message.includes('maximum number of uses') ||
            err.message.includes('already used') ||
            err.message.includes('does not meet minimum')) {
          throw err;
        }
        // For unexpected errors, retry
        console.error(`Unexpected error on attempt ${attempt + 1}:`, err.message);
        if (attempt === MAX_RETRIES - 1) {
          throw new Error(`Failed to redeem coupon after ${MAX_RETRIES} attempts: ${err.message}`);
        }
        await sleep(Math.random() * 50 * (attempt + 1));
      }
    }

    throw new Error(`Failed to redeem coupon "${couponCode}" after ${MAX_RETRIES} retries due to contention`);

  } finally {
    // Always release the distributed lock
    await redis.del(lockKey);
  }
}

/**
 * Alternative: Redeem using a Lua script for fully atomic operation
 * This is the most robust approach for high-traffic scenarios
 */
async function redeemCouponAtomic(couponCode, userId, orderAmount) {
  const luaScript = `
    local couponKey = KEYS[1]
    local usageKey = KEYS[2]
    local userCouponsKey = KEYS[3]
    local userId = ARGV[1]
    local orderAmount = tonumber(ARGV[2])
    local nowTimestamp = tonumber(ARGV[3])

    -- Check coupon exists
    local exists = redis.call('EXISTS', couponKey)
    if exists == 0 then
      return cjson.encode({error = "Coupon does not exist"})
    end

    -- Get all coupon data
    local couponData = redis.call('HGETALL', couponKey)
    local coupon = {}
    for i = 1, #couponData, 2 do
      coupon[couponData[i]] = couponData[i + 1]
    end

    -- Check active
    if coupon['active'] ~= 'true' then
      return cjson.encode({error = "Coupon is no longer active"})
    end

    -- Check expiration (compare timestamps in milliseconds)
    -- We'll parse the ISO date on the Node side and pass epoch ms
    local expiresAtMs = tonumber(ARGV[4])
    if nowTimestamp > expiresAtMs then
      return cjson.encode({error = "Coupon has expired"})
    end

    -- Check max uses
    local currentUses = tonumber(coupon['currentUses'])
    local maxUses = tonumber(coupon['maxUses'])
    if currentUses >= maxUses then
      return cjson.encode({error = "Coupon has reached maximum uses"})
    end

    -- Check if user already used
    local alreadyUsed = redis.call('SISMEMBER', usageKey, userId)
    if alreadyUsed == 1 then
      return cjson.encode({error = "User has already used this coupon"})
    end

    -- Check minimum order amount
    local minOrderAmount = tonumber(coupon['minOrderAmount'] or '0')
    if orderAmount < minOrderAmount then
      return cjson.encode({error = "Order amount below minimum"})
    end

    -- Calculate discount
    local discountValue = tonumber(coupon['discountValue'])
    local discount = 0
    if coupon['discountType'] == 'percentage' then
      discount = orderAmount * (discountValue / 100)
    else
      discount = discountValue
    end
    if discount > orderAmount then
      discount = orderAmount
    end

    -- Apply redemption atomically
    redis.call('HINCRBY', couponKey, 'currentUses', 1)
    redis.call('SADD', usageKey, userId)
    redis.call('SADD', userCouponsKey, ARGV[1])

    -- Deactivate if max uses reached
    if currentUses + 1 >= maxUses then
      redis.call('HSET', couponKey, 'active', 'false')
    end

    return cjson.encode({
      success = true,
      discount = discount,
      discountType = coupon['discountType'],
      discountValue = discountValue,
      remainingUses = maxUses - (currentUses + 1)
    })
  `;

  const couponKey = COUPON_KEY(couponCode);
  const usageKey = COUPON_USAGE_KEY(couponCode);
  const userCouponsKey = USER_COUPONS_KEY(userId);

  // Get expiration timestamp for the coupon
  const expiresAtStr = await redis.hget(couponKey, 'expiresAt');
  const expiresAtMs = expiresAtStr ? new Date(expiresAtStr).getTime() : 0;
  const nowMs = Date.now();

  const result = await redis.eval(
    luaScript,
    3,
    couponKey,
    usageKey,
    userCouponsKey,
    userId,
    orderAmount.toString(),
    nowMs.toString(),
    expiresAtMs.toString()
  );

  const parsed = JSON.parse(result);

  if (parsed.error) {
    throw new Error(parsed.error);
  }

  const redemptionResult = {
    success: true,
    couponCode,
    userId,
    originalAmount: orderAmount,
    discountType: parsed.discountType,
    discountValue: parsed.discountValue,
    discountApplied: parsed.discount,
    finalAmount: Math.max(0, orderAmount - parsed.discount),
    redeemedAt: new Date().toISOString(),
    remainingUses: parsed.remainingUses
  };

  console.log(`[Atomic] Coupon "${couponCode}" redeemed by user "${userId}": -$${parsed.discount.toFixed(2)}`);
  return redemptionResult;
}

/**
 * Get coupon details
 */
async function getCoupon(couponCode) {
  const couponKey = COUPON_KEY(couponCode);
  const couponData = await redis.hgetall(couponKey);

  if (!couponData || !couponData.code) {
    return null;
  }

  return {
    ...couponData,
    currentUses: parseInt(couponData.currentUses, 10),
    maxUses: parseInt(couponData.maxUses, 10),
    discountValue: parseFloat(couponData.discountValue),
    minOrderAmount: parseFloat(couponData.minOrderAmount),
    active: couponData.active === 'true'
  };
}

/**
 * Deactivate a coupon
 */
async function deactivateCoupon(couponCode) {
  const couponKey = COUPON_KEY(couponCode);
  const exists = await redis.exists(couponKey);
  if (!exists) {
    throw new Error(`Coupon "${couponCode}" does not exist`);
  }
  await redis.hset(couponKey, 'active', 'false');
  console.log(`Coupon "${couponCode}" deactivated`);
}

/**
 * Get all users who redeemed a coupon
 */
async function getCouponUsers(couponCode) {
  const usageKey = COUPON_USAGE_KEY(couponCode);
  return redis.smembers(usageKey);
}

/**
 * Get all coupons used by a user
 */
async function getUserCoupons(userId) {
  const userCouponsKey = USER_COUPONS_KEY(userId);
  return redis.smembers(userCouponsKey);
}

// Helper functions
function calculateDiscount(couponData, orderAmount) {
  const discountValue = parseFloat(couponData.discountValue);

  if (couponData.discountType === 'percentage') {
    return Math.min(orderAmount, orderAmount * (discountValue / 100));
  } else {
    // Fixed discount
    return Math.min(orderAmount, discountValue);
  }
}

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

